const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const citaDate = new Date(item.json.fecha);
  const diffDays = Math.floor((now - citaDate) / (1000 * 60 * 60 * 24));

  // Seguimiento 24h después (1 día)
  if (diffDays === 1 && !item.json.seguimiento_24h) {
    results.push({
      json: {
        ...item.json,
        tipo_seguimiento: '24h',
        dias_transcurridos: diffDays
      }
    });
  }
  // Check-in 7 días
  else if (diffDays === 7 && !item.json.seguimiento_7d) {
    results.push({
      json: {
        ...item.json,
        tipo_seguimiento: '7d',
        dias_transcurridos: diffDays
      }
    });
  }
  // Reactivación 30 días
  else if (diffDays === 30 && !item.json.seguimiento_30d) {
    results.push({
      json: {
        ...item.json,
        tipo_seguimiento: '30d',
        dias_transcurridos: diffDays
      }
    });
  }
}

return results;

// Formatear número de teléfono para WhatsApp Cloud API
const item = $input.item.json;
let telefono = item.telefono;

// Limpiar el número
telefono = telefono.toString().replace(/[\s\-\(\)\+]/g, '');

// Agregar código de país si no lo tiene
if (!telefono.startsWith('506')) {
  telefono = '506' + telefono;
}

// Crear mensaje según tipo de seguimiento
let mensaje = '';

if (item.tipo_seguimiento === '24h') {
  mensaje = `Hola ${item.nombre} 👋

¿Cómo se siente después de su consulta de ayer?

Esperamos que esté siguiendo las indicaciones y sintiéndose mejor cada día 💚

*Recuerde:*
• Seguir las recomendaciones
• Mantener la alimentación sugerida
• Tomar sus productos naturales

Si tiene dudas, estamos aquí para ayudarle.

📞 2770-3198 / 8313-3198

Clínica Dr. William Cruz 🏥`;
} else if (item.tipo_seguimiento === '7d') {
  mensaje = `Hola ${item.nombre} 👋

¿Cómo se siente después de su consulta?

Ha pasado una semana y nos gustaría saber sobre su progreso 💚

*¿Ha notado mejoría?*
¿Tiene alguna pregunta sobre su tratamiento?

Estamos aquí para ayudarle en su proceso de sanación natural.

📞 2770-3198 / 8313-3198
🌐 clinicadrwilliamcruz.com

Clínica Dr. William Cruz 🌿`;
} else {
  mensaje = `Hola ${item.nombre} 👋

Han pasado 30 días desde su última consulta y *nos gustaría saber de usted* 💚

🌿 La medicina natural requiere seguimiento constante para resultados óptimos.

*¿Le gustaría agendar una consulta de seguimiento?*

Puede comunicarse con nosotros:
📞 2770-3198 / 8313-3198
🌐 clinicadrwilliamcruz.com

¡Le extrañamos!
Clínica Dr. William Cruz 🏥`;
}

return {
  json: {
    ...item,
    telefono_whatsapp: telefono,
    mensaje_whatsapp: mensaje
  }
};
